package com.google.gson.extras.examples.rawcollections;

import static org.mockito.Mockito.mockStatic;
import static org.mockito.Mockito.when;

import java.io.ByteArrayOutputStream;
import java.io.PrintStream;
import java.util.Collection;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonParser;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class RawCollectionsExampleTest {

  private final PrintStream originalOut = System.out;
  private ByteArrayOutputStream outContent;

  private MockedStatic<Gson> gsonStaticMock;
  private MockedStatic<JsonParser> jsonParserStaticMock;

  @BeforeEach
  void setUp() {
    outContent = new ByteArrayOutputStream();
    System.setOut(new PrintStream(outContent));
  }

  @AfterEach
  void tearDown() {
    System.setOut(originalOut);
    if (gsonStaticMock != null) {
      gsonStaticMock.close();
    }
    if (jsonParserStaticMock != null) {
      jsonParserStaticMock.close();
    }
  }

  @Test
  void testMain_printsExpectedOutput() throws Exception {
    // We do not mock Gson or JsonParser here to test real behavior

    RawCollectionsExample.main(new String[0]);

    String output = outContent.toString().replaceAll("\\r\\n", "\n");
    // Check first line contains the JSON string of the raw collection
    org.junit.jupiter.api.Assertions.assertTrue(output.contains("Using Gson.toJson() on a raw collection: [\"hello\",5,{\"type\":\"GREETINGS\",\"source\":\"guest\"}]"));
    // Check second line contains the formatted output with message, number and event
    org.junit.jupiter.api.Assertions.assertTrue(output.contains("Using Gson.fromJson() to get: hello, 5, Event[type=GREETINGS, source=guest]"));
  }
}
